#include <iostream>
#include <vector>
#include <string>

int main() {
    std::vector<std::string> fruits = {"apple", "banana", "cherry"};
    std::cout << fruits[0] << std::endl;   // apple
    fruits.push_back("orange");
    for (const auto& f : fruits) std::cout << f << " "; // apple banana cherry orange
    std::cout << std::endl;
    fruits.pop_back();
    std::cout << fruits.size() << std::endl; // 3
    return 0;
}

