cpp.code:
#include <iostream>
#include <map>
#include <string>

int main() {
    std::map<std::string, std::string> person;
    person["name"] = "Alice";
    person["age"] = "25";
    std::cout << person["name"] << std::endl;  // Alice
    person["city"] = "Moscow";
    person.erase("age");
    if (person.find("age") == person.end())
        std::cout << "age not found" << std::endl;
    return 0;
}

